// Generate all (query × page) combinations so the loop processes each one.
// 10 queries × 3 pages = 30 HTTP requests → ~100-120 LinkedIn profiles after filtering.
const config = $input.first().json;
const queries = (config.SEARCH_QUERIES || '').split('\n').map(q => q.trim()).filter(Boolean);
if (!queries.length) throw new Error('No queries found in SEARCH_QUERIES.');

const pages = [1, 11, 21]; // 3 pages of 10 results each
const output = [];
for (const q of queries) {
  for (const start of pages) {
    output.push({ json: {
      search: q,
      start,
      _email: config.YOUR_EMAIL,
      _goal: config.SEARCH_GOAL,
      _ideal: config.IDEAL_LEAD_DESCRIPTION,
      _sheetUrl: config.SHEET_URL
    }});
  }
}
return output;

// Extract LinkedIn profiles from Google search results.
// Filters to /in/ URLs only. Pulls name, title, snippet cleanly.
// Passes config fields forward for AI scoring downstream.

function cleanText(t) {
  return (t || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
}

function parseName(title) {
  // LinkedIn titles are usually: "First Last - Title | LinkedIn" or "First Last | LinkedIn"
  const noLinkedIn = title.replace(/\|?\s*LinkedIn\s*/gi, '').trim();
  const dashIdx = noLinkedIn.search(/\s[-–—]\s/);
  const namePart = dashIdx > 0 ? noLinkedIn.slice(0, dashIdx).trim() : noLinkedIn.split('|')[0].trim();
  const words = namePart.split(' ').filter(w => w.length > 0);
  // Validate: name should be 1-4 words, all starting with uppercase
  if (words.length >= 1 && words.length <= 4 && words.every(w => /^[A-ZÀ-Ö]/.test(w))) {
    return { firstName: words[0] || '', lastName: words.slice(1).join(' ') || '' };
  }
  return { firstName: '', lastName: '' };
}

function parseRoleAndCompany(title) {
  // "First Last - Role at Company | LinkedIn" or "First Last - Role | Company | LinkedIn"
  const noLinkedIn = title.replace(/\|?\s*LinkedIn\s*/gi, '').trim();
  const dashIdx = noLinkedIn.search(/\s[-–—]\s/);
  if (dashIdx < 0) return { role: '', company: '' };
  const afterDash = noLinkedIn.slice(dashIdx + 3).trim();
  // Try "Role at Company"
  const atMatch = afterDash.match(/^(.+?)\s+at\s+(.+?)(?:\s*\||$)/i);
  if (atMatch) return { role: atMatch[1].trim(), company: atMatch[2].trim() };
  // Try "Role | Company"
  const pipeMatch = afterDash.split('|');
  if (pipeMatch.length >= 2) return { role: pipeMatch[0].trim(), company: pipeMatch[1].trim() };
  return { role: afterDash.split('|')[0].trim(), company: '' };
}

const inJson = $input.first().json;
const items = inJson.items || [];
const meta = {
  _email: inJson._email || '',
  _goal: inJson._goal || '',
  _ideal: inJson._ideal || '',
  _sheetUrl: inJson._sheetUrl || ''
};

// The HTTP node merges the search params into the response — pull them from context
const allItems = $input.all();
let email = '', goal = '', ideal = '', sheetUrl = '';
for (const it of allItems) {
  if (it.json._email) { email = it.json._email; goal = it.json._goal; ideal = it.json._ideal; sheetUrl = it.json._sheetUrl; break; }
}

const output = [];
for (const r of items) {
  const link = (r.link || r.formattedUrl || '').split('?')[0]; // strip query params
  if (!link.includes('linkedin.com/in/')) continue; // only personal profiles

  const title = cleanText(r.title || r.htmlTitle || '');
  const snippet = cleanText(r.snippet || r.htmlSnippet || '');
  if (!title || title.length < 5) continue;

  const { firstName, lastName } = parseName(title);
  const { role, company } = parseRoleAndCompany(title);

  // Infer location from snippet if possible
  let location = '';
  const locMatch = snippet.match(/(?:based in|located in|\bin\b)\s+([A-Z][a-zA-Z ,]+(?:CA|NY|London|Berlin|Bali|Singapore)?)/i)
    || snippet.match(/(San Francisco(?:\s+Bay\s+Area)?|Bay Area|New York|London|Berlin|Bali|Singapore|Austin|Miami|Los Angeles)/i);
  if (locMatch) location = locMatch[1].trim();

  output.push({ json: {
    firstName,
    lastName,
    role,
    company,
    location,
    linkedIn: link,
    rawTitle: title,
    rawSnippet: snippet,
    _email: email,
    _goal: goal,
    _ideal: ideal,
    _sheetUrl: sheetUrl
  }});
}

if (!output.length) return [{ json: { _empty: true } }];
return output;

// Batch profiles into groups of 10 to send to OpenAI efficiently.
const items = $input.all().filter(i => !i.json._empty);
if (!items.length) return [{ json: { _empty: true } }];

const batchSize = 10;
const batches = [];
let meta = {};
for (const it of items) {
  meta = { _email: it.json._email, _goal: it.json._goal, _ideal: it.json._ideal, _sheetUrl: it.json._sheetUrl };
}

for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize).map(it => ({
    linkedIn: it.json.linkedIn,
    firstName: it.json.firstName,
    lastName: it.json.lastName,
    role: it.json.role,
    company: it.json.company,
    location: it.json.location,
    title: it.json.rawTitle,
    snippet: it.json.rawSnippet
  }));
  batches.push({ json: { batch, ...meta } });
}
return batches;

