// Parse AI response, filter junk + low scores, format for Google Sheets.
const items = $input.all();
const output = [];

for (const item of items) {
  const r = item.json;
  let text = r?.message?.content || r?.choices?.[0]?.message?.content || r?.text || '';
  if (!text) continue;

  text = text.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  let leads = [];
  try {
    leads = JSON.parse(text);
    if (!Array.isArray(leads)) leads = [leads];
  } catch(e) {
    const m = text.match(/\[.*\]/s);
    if (m) { try { leads = JSON.parse(m[0]); } catch(e2) { continue; } }
    else continue;
  }

  for (const lead of leads) {
    if (lead.isJunk === true) continue;
    const score = lead.relevanceScore || 0;
    if (score < 0.5) continue;
    if (!lead.linkedIn) continue;

    const url = lead.linkedIn.toLowerCase().replace(/\/+$/, '');
    const fn = (lead.firstName || '').toLowerCase().trim();
    const ln = (lead.lastName || '').toLowerCase().trim();
    const co = (lead.company || '').toLowerCase().trim();

    output.push({ json: {
      'First Name': lead.firstName || '',
      'Last Name': lead.lastName || '',
      'LinkedIn': lead.linkedIn || '',
      'Role': lead.role || '',
      'Company': lead.company || '',
      'Role Category': lead.roleCategory || 'Other',
      'Location': lead.location || '',
      'Relevance Score': score,
      'Reach Out Reason': lead.reachOutReason || '',
      'Query Group': '',
      'Is Duplicate': 'No',
      'Date Added': new Date().toISOString().split('T')[0],
      'Dedupe Key': `${fn} ${ln}||${co}||${url}`,
      '_email': r._email || '',
      '_goal': r._goal || '',
      '_sheetUrl': r._sheetUrl || ''
    }});
  }
}

return output.length ? output : [{ json: { _empty: true } }];

const data = $json;
const all = (data.allLeads || []).filter(l => !l._empty);
const meta = all[0] || {};
const goal = meta._goal || 'Lead Search';
const sendTo = meta._email || 'me';
const today = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

if (!all.length) {
  return [{ json: {
    emailHtml: `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;background:#f5f5f5;padding:20px"><div style="max-width:600px;margin:0 auto;background:#fff;border-radius:12px;padding:40px;text-align:center"><div style="font-size:48px">✅</div><h2>No New Leads Found</h2><p style="color:#64748b">${today}</p><p style="color:#94a3b8;font-size:13px">All results scored below 0.5 or were already in your sheet.</p></div></body></html>`,
    subject: 'ℹ️ Lead Engine: No New Leads Today',
    sendTo
  }}];
}

const top10 = [...all].sort((a,b) => (parseFloat(b['Relevance Score'])||0) - (parseFloat(a['Relevance Score'])||0)).slice(0,10);
const total = all.length;
const strong = all.filter(l => (parseFloat(l['Relevance Score'])||0) >= 0.7).length;
const likely = all.filter(l => { const s=parseFloat(l['Relevance Score'])||0; return s>=0.5 && s<0.7; }).length;

const badge = s => s>=0.7 ? {bg:'#dcfce7',fg:'#15803d',lbl:'★ Strong'} : {bg:'#fef9c3',fg:'#854d0e',lbl:'◆ Likely'};

const card = (l, i) => {
  const name = [l['First Name'],l['Last Name']].filter(Boolean).join(' ') || 'Unknown';
  const score = parseFloat(l['Relevance Score'])||0;
  const {bg,fg,lbl} = badge(score);
  const sub = [l['Role'],l['Company']].filter(Boolean).join(' @ ');
  const reason = l['Reach Out Reason']||'';
  return `<div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;padding:16px 18px;margin-bottom:10px;position:relative">
  <div style="position:absolute;top:14px;right:14px;font-size:11px;font-weight:800;color:#cbd5e1">#${i+1}</div>
  <div style="margin-bottom:4px;padding-right:28px">
    ${l['LinkedIn'] ? `<a href="${l['LinkedIn']}" style="font-size:15px;font-weight:700;color:#1d4ed8;text-decoration:none">${name}</a>` : `<span style="font-size:15px;font-weight:700">${name}</span>`}
    <span style="display:inline-block;font-size:10px;font-weight:700;padding:2px 8px;border-radius:20px;margin-left:8px;vertical-align:middle;background:${bg};color:${fg}">${lbl} ${(score*100).toFixed(0)}%</span>
  </div>
  ${sub ? `<div style="font-size:13px;color:#374151;margin-bottom:3px">${sub}</div>` : ''}
  ${l['Location'] ? `<div style="font-size:12px;color:#6b7280;margin-bottom:6px">📍 ${l['Location']}</div>` : ''}
  ${reason ? `<div style="font-size:12px;background:#eff6ff;border-left:3px solid #3b82f6;padding:8px 10px;border-radius:0 6px 6px 0;color:#1e40af;line-height:1.5">💡 ${reason}</div>` : ''}
</div>`;
};

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;background:#f1f5f9;margin:0;padding:20px">
<div style="max-width:680px;margin:0 auto;background:#fff;border-radius:14px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.09)">
  <div style="background:linear-gradient(135deg,#0f172a,#1e3a5f);color:#fff;padding:28px 32px">
    <h1 style="margin:0 0 4px;font-size:22px;font-weight:800">🎯 Top ${Math.min(10,top10.length)} Leads</h1>
    <p style="margin:0 0 3px;font-size:13px;opacity:.8;font-style:italic">${goal}</p>
    <p style="margin:0;font-size:12px;opacity:.55">${today}</p>
  </div>
  <div style="display:flex;border-bottom:1px solid #e2e8f0">
    <div style="flex:1;padding:14px 20px;text-align:center;border-right:1px solid #e2e8f0"><div style="font-size:26px;font-weight:800;color:#0f172a">${total}</div><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.05em">Saved Today</div></div>
    <div style="flex:1;padding:14px 20px;text-align:center;border-right:1px solid #e2e8f0"><div style="font-size:26px;font-weight:800;color:#15803d">${strong}</div><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.05em">★ Strong</div></div>
    <div style="flex:1;padding:14px 20px;text-align:center"><div style="font-size:26px;font-weight:800;color:#854d0e">${likely}</div><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.05em">◆ Likely</div></div>
  </div>
  <div style="padding:20px 32px 8px">${top10.map(card).join('')}</div>
  <div style="padding:12px 32px 20px;text-align:center;color:#94a3b8;font-size:12px;border-top:1px solid #e2e8f0">Deduped by LinkedIn URL · GPT-4o-mini scoring · Only ≥0.5 saved</div>
</div></body></html>`;

const top = top10[0]||{};
const topName = [top['First Name'],top['Last Name']].filter(Boolean).join(' ');
return [{ json: { emailHtml: html, sendTo, subject: `🎯 ${strong} Strong + ${likely} Likely Leads — ${topName||'See inside'} (${new Date().toLocaleDateString('en-US',{month:'short',day:'numeric'})})` } }];
